import type { StudioLanguage } from "@/lib/studioflow/language";

// ---------------------------------------------------------------------------
// NivaDesk user guide — content translations.
//
// Each entry maps an English source string (from TREE_EN in guide.ts) to its
// translation. getGuideTree() walks the canonical English tree and swaps each
// title / paragraph / bullet through the matching language dictionary; any
// string without a translation falls back to English. So a partially filled
// language still renders — every menu and card is shown, untranslated lines
// just stay English.
//
// English is the source (no dict) and Türkçe has its own full tree (TREE_TR).
// ---------------------------------------------------------------------------

